sysml2Model(name = "AUTOSAR_ECU_Model") {
    // Hardware leaf parts
    val cpuCore = partDef(name = "CPU Core")
    val ram = partDef(name = "RAM")
    val flashMemory = partDef(name = "Flash Memory")

    // Hardware inheritance structure
    val communicationController = partDef(name = "Communication Controller") {
        isAbstract = true
    }
    val canController = partDef(name = "CAN Controller") {
        generalization(generalId = communicationController.id)
    }
    val linController = partDef(name = "LIN Controller") {
        generalization(generalId = communicationController.id)
    }
    val ethernetController = partDef(name = "Ethernet Controller") {
        generalization(generalId = communicationController.id)
    }

    // BSW inheritance structure
    val bswModule = partDef(name = "BSW Module") {
        isAbstract = true
    }
    val mcal = partDef(name = "MCAL") {
        generalization(generalId = bswModule.id)
    }
    val canStack = partDef(name = "CAN Stack") {
        generalization(generalId = bswModule.id)
    }
    val ethernetStack = partDef(name = "Ethernet Stack") {
        generalization(generalId = bswModule.id)
    }
    val os = partDef(name = "OS") {
        generalization(generalId = bswModule.id)
    }
    val watchdog = partDef(name = "Watchdog") {
        generalization(generalId = bswModule.id)
    }

    // Application leaf parts
    val vfb = partDef(name = "Virtual Functional Bus")
    val softwareComponent = partDef(name = "Software Component")

    // Composite parts
    val microcontroller = partDef(name = "Microcontroller") {
        part(name = "core", typeId = cpuCore.id)
        part(name = "ram", typeId = ram.id)
        part(name = "flash", typeId = flashMemory.id)
        part(name = "can", typeId = canController.id, multiplicity = multiplicity(1, null))
        part(name = "lin", typeId = linController.id, multiplicity = multiplicity(0, null))
        part(name = "eth", typeId = ethernetController.id, multiplicity = multiplicity(0, null))
    }

    val hardwareLayer = partDef(name = "Hardware Layer") {
        part(name = "mcu", typeId = microcontroller.id)
    }

    val bswLayer = partDef(name = "BSW Layer") {
        part(name = "mcal", typeId = mcal.id)
        part(name = "canStack", typeId = canStack.id)
        part(name = "ethStack", typeId = ethernetStack.id)
        part(name = "os", typeId = os.id)
        part(name = "wdg", typeId = watchdog.id)
    }

    val applicationLayer = partDef(name = "Application Layer") {
        part(name = "vfb", typeId = vfb.id)
        part(name = "swc", typeId = softwareComponent.id, multiplicity = multiplicity(1, null))
    }

    val ecu = partDef(name = "ECU") {
        part(name = "hw", typeId = hardwareLayer.id)
        part(name = "bsw", typeId = bswLayer.id)
