c4Model(name = "Video Streaming Platform") {
    val viewer = person(name = "Viewer") { description = "Watches video content and receives recommendations." }
    val contentManager = person(name = "Content Manager") { description = "Adds new titles and curates video metadata." }

    val cdn = softwareSystem(name = "Content Delivery Network (CDN)") { external = true; description = "Delivers video stream files to viewers." }
    val drmService = softwareSystem(name = "Licensing & DRM Service") { external = true; description = "Handles digital rights management and license verification for video playback." }

    lateinit var webPlayer: Any
    lateinit var apiGateway: Any
    lateinit var recommendationService: Any
    lateinit var contentManagementService: Any
    lateinit var transcodingPipeline: Any
    lateinit var analyticsService: Any
    lateinit var catalogDatabase: Any

    val streamingPlatform = softwareSystem(name = "Video Streaming Platform") {
        webPlayer = container(name = "Web Player") { technology = "SPA, TypeScript/React"; description = "Provides video playback and personalized content recommendations to the viewer." }
        apiGateway = container(name = "API Gateway") { technology = "Kotlin/Ktor"; description = "Handles all incoming requests from the web player and content management service." }
        recommendationService = container(name = "Recommendation Service") { technology = "Python/TensorFlow"; description = "Generates personalized video recommendations using a machine learning algorithm." }
        contentManagementService = container(name = "Content Management Service") { technology = "Go"; description = "Provides an interface for content managers to add and update video content." }
        transcodingPipeline = container(name = "Transcoding Pipeline") { technology = "Java/FFmpeg"; description = "Processes uploaded raw video material into various streaming formats." }
        analyticsService = container(name = "Analytics Service") { technology = "Scala/Spark"; description = "Collects and analyzes viewing behavior to feed the recommendation algorithm." }
        catalogDatabase = container(name = "Catalog Database") { technology = "PostgreSQL"; description = "Stores video metadata, user information, and transcoded file locations." }
    }

    // User-facing relationships
    relationship(source = viewer, target = webPlayer) { description = "Uses"; technology = "HTTPS" }
    relationship(source = viewer, target = cdn) { description = "Streams video from"; technology = "HTTPS" }
    relationship(source = contentManager, target = contentManagementService) { description = "Uses to manage content"; technology = "HTTPS" }

    // Internal and external service relationships
    relationship(source = webPlayer, target = apiGateway) { description = "Makes API calls to get metadata and recommendations"; technology = "HTTPS/GraphQL" }
    relationship(source = webPlayer, target = drmService) { description = "Verifies playback rights with"; technology = "HTTPS" }

    relationship(source = contentManagementService, target = transcodingPipeline) { description = "Submits raw video for processing"; technology = "AMQP" }
    relationship(source = contentManagementService, target = catalogDatabase) { description = "Writes/Reads video metadata"; technology = "JDBC" }

    relationship(source = apiGateway, target = recommendationService) { description = "Gets recommendations from"; technology = "gRPC" }
    relationship(source = apiGateway, target = catalogDatabase) { description = "Gets video metadata from"; technology = "JDBC" }
    relationship(source = apiGateway, target = analyticsService) { description = "Sends viewing events to"; technology = "REST/JSON" }

    relationship(source = transcodingPipeline, target = catalogDatabase) { description = "Updates video status and file locations"; technology = "JDBC" }
    relationship(source = transcodingPipeline, target = cdn) { description = "Uploads transcoded video files to"; technology = "S3 API" }

    relationship(source = analyticsService, target = recommendationService) { description = "Provides processed viewing data to"; technology = "Batch Process" }

    containerDiagram(name = "Video Streaming Platform - Container View") {
        system = streamingPlatform
        showExternalSystems = true
    }
}

