c4Model(name = "Autonomous Driving Test Platform") {
    val testEngineer = person(name = "Test Engineer") { description = "Defines test campaigns and scenarios." }
    val fleetManager = person(name = "Fleet Manager") { description = "Monitors vehicle status and health." }
    val dataAnalyst = person(name = "Data Analyst") { description = "Examines test runs and KPIs for deviations." }

    val testVehicles = softwareSystem(name = "Real Test Vehicles") {
        description = "Externally managed test fleet that collects and uploads sensor data."
        external = true
    }
    val simulationEnv = softwareSystem(name = "Simulation Environment") {
        description = "Performs virtual validation using a physics engine and sensor models."
        external = true
    }
    val hdMapService = softwareSystem(name = "HD Map Service") {
        description = "Provides high-resolution map material for simulation."
        external = true
    }
    val ticketingSystem = softwareSystem(name = "Requirements and Ticketing System") {
        description = "External system for tracking requirements and reported issues."
        external = true
    }

    val testPlatform = softwareSystem(name = "Test Platform") {
        description = "Cloud infrastructure for managing and executing autonomous driving tests."

        val webInterface = container(name = "Web Interface") {
            technology = "React, TypeScript"
            description = "Provides UI for test engineers to define campaigns and fleet managers to monitor vehicles."
        }
        val ingestService = container(name = "Ingest Service") {
            technology = "Kafka, Go"
            description = "Receives and queues measurement and sensor data from test vehicles."
        }
        val dataLake = container(name = "Data Lake") {
            technology = "AWS S3, Parquet"
            description = "Stores all raw and processed test data, including sensor readings and results."
        }
        val orchestrator = container(name = "Orchestrator") {
            technology = "Kubernetes, Python"
            description = "Schedules physical and virtual test runs based on campaigns."
        }
        val scenarioCatalog = container(name = "Scenario Catalog") {
            technology = "PostgreSQL"
            description = "Manages test cases, scenarios, and their parameters."
        }
        val evaluationService = container(name = "Evaluation Service") {
            technology = "Python, Pandas"
            description = "Checks test run results against expected values and computes KPIs."
        }
        val analysisWorkbench = container(name = "Analysis Workbench") {
            technology = "JupyterHub, Spark"
            description = "Provides a notebook interface and KPI computation tools for data analysts."
        }
    }

    relationship(source = testEngineer, target = testPlatform.webInterface) { description = "Defines test campaigns" }
    relationship(source = fleetManager, target = testPlatform.webInterface) { description = "Monitors vehicle status" }
    relationship(source = dataAnalyst, target = testPlatform.analysisWorkbench) { description = "Examines collected runs and KPIs" }
    relationship(source = testPlatform.webInterface, target = testPlatform.orchestrator) { description = "Schedules test runs"; technology = "REST/JSON" }
    relationship(source = testPlatform.webInterface, target = testPlatform.scenarioCatalog) { description = "Manages test cases"; technology = "REST/JSON" }
    relationship(source = testVehicles, target = testPlatform.ingestService) { description = "Uploads measurement and sensor data"; technology = "MQTT/Protobuf" }
    relationship(source = testPlatform.ingestService, target = testPlatform.dataLake) { description = "Stores raw data" }
    relationship(source = testPlatform.orchestrator, target = testPlatform.scenarioCatalog) { description = "Retrieves test cases"; technology = "SQL" }
    relationship(source = testPlatform.orchestrator, target = testPlatform.dataLake) { description = "Retrieves data for test runs"; technology = "S3 API" }
    relationship(source = testPlatform.orchestrator, target = testPlatform.evaluationService) { description = "Triggers result checks" }
    relationship(source = testPlatform.evaluationService, target = testPlatform.dataLake) { description = "Reads results and expected values"; technology = "S3 API" }
    relationship(source = testPlatform.analysisWorkbench, target = testPlatform.dataLake) { description = "Accesses data directly for analysis"; technology = "Spark/S3 API" }
    relationship(source = testPlatform.orchestrator, target = simulationEnv) { description = "Dispatches scenarios for virtual validation"; technology = "REST/JSON" }
    relationship(source = simulationEnv, target = testPlatform.orchestrator) { description = "Reports results back"; technology = "REST/JSON" }
    relationship(source = testPlatform.analysisWorkbench, target = ticketingSystem) { description = "Reports detected deviations"; technology = "REST/JSON" }
    relationship(source = simulationEnv, target = hdMapService) { description = "Retrieves high-resolution map material"; technology = "REST/API" }

    containerDiagram(name = "Autonomous Driving Test Platform - Container View") {
        system = testPlatform
        showExternalSystems = true
    }
}
